import java.util.HashMap;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        long[] prefix = new long[n + 1];
        for (int i = 1; i <= n; i++) {
            prefix[i] = prefix[i - 1] + nums[i - 1];
        }

        HashMap<Long, Long> modMap = new HashMap<>();
        long mod = prefix[0] % k;
        modMap.put(mod, 0 - prefix[0]);

        long prevDP = 0;
        for (int i = 1; i <= n; i++) {
            long currentS = prefix[i];
            long currentMod = currentS % k;
            long candidate = -Long.MAX_VALUE;
            if (modMap.containsKey(currentMod)) {
                candidate = modMap.get(currentMod) + currentS;
            }
            long currentDP = Math.max(prevDP, candidate);
            long val = currentDP - currentS;
            if (modMap.containsKey(currentMod)) {
                if (val > modMap.get(currentMod)) {
                    modMap.put(currentMod, val);
                }
            } else {
                modMap.put(currentMod, val);
            }
            prevDP = currentDP;
        }

        long totalSum = prefix[n];
        return totalSum - prevDP;
    }
}
